var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"행색과 행동 양상으로 미루어보아 민병대 분들이시군요. 소문은 익히 들었습니다.","JPN":"身なりと行動からして民兵隊の方々ですね。噂は聞いております。","ENG":"Judging by your behavior, you must be the Militia. I've heard a lot about you.","TWN":"從你們的裝扮和行動看來，應該是民兵隊的吧？久仰大名。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L3_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"제 행적 때문에 오셨으리라고 짐작되지만……. 쉽게 목숨을 내어드릴 수는 없군요.","JPN":"以前、私が犯した罪の件でお越しになったのでしょうが……そう簡単に命を奪われるわけにはいきません。","ENG":"I'm sure you're here to make me pay for what I did... But I won't surrender that easily.","TWN":"雖然我有猜到你們是為我而來的……但我無法輕易交出自己的性命。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"말도 안 돼. 이게 보통 사람의 완력이라고?","JPN":"あり得ない。これが普通の人間の腕力だって？","ENG":"What the heck? No normal human can be this powerful...!","TWN":"太誇張，這是普通人的腕力嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"사람은 위기 상황에 처하면 평소와 다른 신체 능력을 발휘한다고 하죠.","JPN":"人は危機状態に陥ると普段とは違う身体能力を発揮すると言われています。","ENG":"Haven't you heard how people display extreme physical strength when they are in life-or-death situations?","TWN":"當人面對危險時，身體會激發出不同於平時的潛能。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 저는 여러분처럼 통증을 느낄 수 없답니다.","JPN":"ですが、私は皆様のように苦痛を感じることができないのです。","ENG":"However, one thing I differ from you all is that I can't feel pain.","TWN":"不過我和你們一樣，是感覺不到疼痛的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"큭……! 빗나갔나!","JPN":"くっ……！　外したか！","ENG":"Kgh...! I missed!","TWN":"唔……！射偏了嗎！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"위기를 경고해 줄 기재가 없으니 항상 위기 상황처럼 긴장하고 지낼 수밖에요.","JPN":"危機を警告してくれる機構がないので、常に危機状態の時のように緊張しているしかありません。","ENG":"And since there is no warning sign for when I'll be attacked, I have no choice but to always stay alert.","TWN":"因為沒有工具可以通知你有危險，所以常常只能處於戒備狀態。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그리고 주위의 기척을 읽는 건, 메이드에게 필수적인 소양이랍니다.","JPN":"それに周囲の気配を感じとるのは、メイドにとって必要不可欠なたしなみです。","ENG":"Furthermore, being able to read the energy around her is one of a maid's required virtues.","TWN":"另外，察覺周圍的動靜是女僕必備的素養。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"빌어먹을, 저 여자에게는 사각도 없나 보군.","JPN":"くそ、あの女には死角もないようだな。","ENG":"Dammit...! It's like this person has no blind spot!","TWN":"該死，那女的似乎沒有盲點！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"안 되겠다. 이유리, 레비아. 타깃과 최대한 멀리 떨어져.","JPN":"仕方ない。カスカベ、レヴィア。なるべくターゲットから遠く離れろ。","ENG":"Forget this. Yuri, Levia, get as far away from the target as possible.","TWN":"這樣不行，李悠麗、莉維亞，盡可能和目標拉開距離。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐? 어떻게 하려고?","JPN":"は？　どうするつもり？","ENG":"What? But why?","TWN":"什麼？你想做什麼？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"설명할 시간 없다! 서둘러!","JPN":"説明する暇はない！　急げ！","ENG":"There's no time to explain! Hurry!","TWN":"我沒時間跟你解釋！動作快！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"우와, 건물이 통째로 무너졌네요? 이게 민우 대장이 준비한 보험이에요?","JPN":"うわ、建物が丸ごと崩れましたよ？　これがマツダ隊長が準備していた保険なんですか？","ENG":"Whoa, the building just collapsed. Is this the backup plan Captain was talking about?","TWN":"哇～整棟樓都垮咧？這就是民宇隊長買的保險嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 부랴부랴 준비했는데 다행히 제대로 터졌군.","JPN":"ああ。急いで準備したんだが、幸いちゃんと爆発したようだな。","ENG":"Yes. I was hurried for it and thank god it worked.","TWN":"沒錯，準備得有點匆促，幸好有順利引爆。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"괜찮나, 이유리?","JPN":"大丈夫か？　カスカベ。","ENG":"You all right, Yuri?","TWN":"李悠麗，你沒事吧？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"콜록, 콜록……!","JPN":"ゲホ、ゲホ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"다음부터는 내 동의부터 받고 무너뜨려! 하마터면 같이 깔릴 뻔했잖아!","JPN":"次からはまず同意を得てからやってくれ！　一歩間違えたら私も一緒に下敷きになってた！","ENG":"Next time, get my approval before doing something like this! You almost buried me alive!","TWN":"下次可以等我說好再引爆嗎！我差點就一起被炸飛咧！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L33_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"미안하다. 이럴 때는 선 조치 후 보고밖에 없어서 말이지.","JPN":"悪い。こういう場合は事後承諾を得るしかなくてな。","ENG":"Sorry, but I needed to act fast.","TWN":"不好意思，這種時候只能先斬後奏。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하여튼 인간인 이상에야, 이걸로……","JPN":"とにかく人間である以上、これで……","ENG":"But her being a human and all... This should─","TWN":"總之普通人被這樣一炸，應該……"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"정성껏 준비하셨을 텐데 당해드리지 못해 죄송합니다.","JPN":"懸命に準備されたんでしょうに、引っかからず申し訳ございません。","ENG":"I'm sorry that your plan didn't work as intended.","TWN":"這是你精心預備的吧？很抱歉，沒能如你所願。"},"stage":{"bg":"SS_MAID_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 저 역시 한 번 당했던 방식에 두 번이나 당해 드릴 수는 없군요.","JPN":"ですが、私もまた一度やられた手口に二度もやられるわけにはいかないのです。","ENG":"But I won't fall for the same trick twice.","TWN":"不過同一種方式，我當然不可能上二次當。"},"stage":{"bg":"SS_MAID_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……무너지는 건물에서 멀쩡하게 빠져나온다고?","JPN":"……崩れた建物から何もなかったように出て来た？","ENG":"She walked out of that unscathed?!","TWN":"……她好端端地從倒塌的大樓內走出來嗎？"},"stage":{"bg":"SS_MAID_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"망할…… 저게 정말 우리랑 같은 인간은 맞는 건가?","JPN":"くそ……本当に俺たちと同じ人間なのか？","ENG":"Dammit...! Is she really just a normal human being?!","TWN":"該死……她真的和我們一樣是普通人嗎？"},"stage":{"bg":"SS_MAID_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 최단경로를 파악하는 관찰력과 과감한 행동력 모두, 메이드가 갖춰야 할 소양입니다.","JPN":"はい。最短経路を把握する観察力と大胆な行動力、すべてメイドが備えるべきたしなみです。","ENG":"Why yes. The ability to figure out the shortest path and take action with certainty are both virtues any maid should have.","TWN":"是的，掌握最短路徑的觀察力，和當機立斷的行動力，這二者都是女僕該具備的素養。"},"stage":{"bg":"SS_MAID_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그렇단 말이지…….","JPN":"なるほどね……","ENG":"Is that so…","TWN":"是喔……"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그렇다면…… 나도 더 이상 봐 주지 않겠어!","JPN":"なら……私ももう手加減しない！","ENG":"Then... I won't go easy on you anymore!","TWN":"既然如此……那我也就不再手下留情囉！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"멈춰! 이유리! 그 상태론 안 돼!","JPN":"やめろ！　カスカベ！　その状態では無理だ！","ENG":"Yuri! Stop! Don't do it!","TWN":"住手！李悠麗！你不是她的對手！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"웃……!","JPN":"うっ……！","ENG":"Ngh...!","TWN":"唔……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L50_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"민우 대장 말이 맞아요, 유리 언니. 무리하면 안 되지.","JPN":"マツダ隊長の言うとおりですよ、ユリさん。無理しちゃダメ。","ENG":"Captain's right, Yuri. You shouldn't strain yourself.","TWN":"悠麗姊姊，民宇隊長說的沒錯，你不要太勉強。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"레비아?! 무작정 달려들면 위험해!","JPN":"レヴィア！？　いきなり飛びかかると危ない！","ENG":"Levia?! It's too dangerous to just charge into her like that!","TWN":"莉維亞？！你就那樣衝上去會有危險！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"안심해, 안심~ 테크닉이라면 나도 안 지거든~","JPN":"大丈夫、大丈夫～テクニックなら私も負けませんから～","ENG":"Don't worry, I'll be fine! Plus, I never lost a battle that required technique!","TWN":"沒事沒事～要比技術的話我是不會輸的～"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"사람을 상대로 망설임 없이 흉기를 휘두르시는군요. 얼마나 많은 사람을 죽인 겁니까?","JPN":"人を相手に何のためらいもなく凶器を振るうんですね。どれほど多くの人を殺してきたのですか？","ENG":"You swing that around in front of people without hesitation. Tell me, how many people have you killed?","TWN":"竟然可以毫不猶豫地對人揮武器，你是殺人無數嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L9_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"어머나, 무서워라~ 살인자 눈에는 살인자만 보이나 봐~","JPN":"やだ、怖～い。人殺しの目にはみんな人殺しに見えちゃうんだ～","ENG":"Gosh, how scary! I guess it takes one to know one, hmm?","TWN":"哎唷，好可怕喔～在殺人犯眼裡大家都是殺人犯嗎～"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"난 그냥 사냥이 취미일 뿐이거든. 딱히 죽이는 건 관심없어.","JPN":"私はただ狩りが趣味なだけなの。別に殺すことには興味ないよ。","ENG":"Hunting is just a hobby of mine. I'm not really interested in killing.","TWN":"我只是喜歡狩獵而已，對殺人可沒興趣。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"고상하게 레저 스포츠라고 할까?","JPN":"上品に言えばレジャースポーツ？","ENG":"I guess you could say that I like the sport of it?","TWN":"說好聽一點，算是休閒運動嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그런 분이…… 왜 저를 노리시는 거죠?","JPN":"そういう方が……どうして私を狙うのですか？","ENG":"Then why... are you aiming that at me?","TWN":"那你……為何會找上我呢？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L14_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"당신에게 죽은 사람들을 대신해 복수하러 왔지.","JPN":"あなたに殺された人たちの代わりに復讐をしに来たの。","ENG":"To get revenge for all those other people you've killed.","TWN":"我們是代替那些被你殺掉的人來報仇的。"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"내 여동생도 네 손에 죽었으니까!","JPN":"妹もあなたの手にかかって死んだんだから！","ENG":"And because you murdered my little sister!","TWN":"我妹妹也是死在你的手裡！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"여동……?!","JPN":"いもう……！？","ENG":"Little sister...?!","TWN":"妹妹……？！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에헷, 뻥이야~","JPN":"えへっ、ウソだよ～","ENG":"Hehe, just kidding!","TWN":"嘿嘿，騙你的啦～"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"커윽……!","JPN":"がはっ……！","ENG":"Kagh...!","TWN":"呃唔……！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"치명상 되시겠습니다, 손님!","JPN":"致命傷になります、お客様！","ENG":"That'll be a critical hit, Miss!","TWN":"客人，這下傷得不輕喔！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"레비아! 사선에서 비켜!","JPN":"レヴィア！　射線から外れろ！","ENG":"Levia! Get out of the way!","TWN":"莉維亞！閃開！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"잘했다, 레비아. 날붙이 다루는 솜씨 하난 인정해 줘야겠군.","JPN":"よくやった、レヴィア。刃物を扱う手さばきだけは認めてやらないとな。","ENG":"Good job, Levia. I guess I gotta give you credit for your skills with sharp edges.","TWN":"做得好，莉維亞。不得不稱讚一下你使用剪刀的技巧呢。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그러게요. 어째 여기 온 뒤로 컨디션이 좋은 거 있죠?","JPN":"ええ。ここに来てからなんだか調子がいいんですよね！","ENG":"I suppose so. And I feel so much better after coming here, you know?","TWN":"就是說，不知道為什麼，來到這裡後就覺得狀態很好呢～"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"운이 좋다는 식으론 납득이 가진 않는다만…… 마지막에 뭐라고 속삭이지 않았나?","JPN":"運がいいというだけでは納得がいかないんだが……最後に何かささやいてなかったか？","ENG":"I don't suppose it was all just luck, but... What did you whisper to her in the end there?","TWN":"要說是單純的運氣好嗎……你最後是不是有唸什麼東西？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"흐흥. 마법의 주문이라고나 할까요.","JPN":"ふふん。魔法のおまじないみたいなものですよ。","ENG":"H-hmm... You could call it something like a magic spell, I suppose.","TWN":"呵呵，魔法咒語嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……그래. 확실히 해치우긴 한 건가?","JPN":"……そうか。それで、やったのは確かか？","ENG":"...Okay. But you did finish the job, right?","TWN":"……就這樣吧，有確實把人處理掉嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"아직 숨이 붙어 있어요. 이대로 두면 아무리 초인이라도 과다출혈로 죽겠지만요.","JPN":"まだ息はしてますよ。このまま放っておけばいくら超人でも出血過多で死ぬでしょうけど。","ENG":"She's still breathing. But even if she's got superpowers, she'll die from blood loss.","TWN":"她還有呼吸，但就這樣放著不管，就算她是超人，也會因為失血過多而亡吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그럼 내가 마무리할게. 오랫동안 고통 줄 생각 없어.","JPN":"それじゃあ、私が終わらせる。長い間苦しませるつもりはない。","ENG":"I'll finish her off. No need to make her suffer.","TWN":"那就由我來收尾吧，我不打算讓她痛苦太久。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하아……. 하…….","JPN":"はあ……は……","ENG":"*Huff...* *Huff...*","TWN":"呼……呼……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"무슨 거래를 하고 풀려났는지 몰라도, 피해자들의 유가족이 전부 동의하진 않았나 보더군.","JPN":"どんな取引をして解放されたのかわからないけど、被害者の遺族がみんな同意したわけじゃなかったんだな。","ENG":"I'm not sure what deal you struck to get out, but it appears that not all the victims' families accepted it.","TWN":"我是不清楚是什麼樣的司法交易，讓你被釋放出來，但看來不是所有的受害者家屬都認同。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……너무 많은 사람을 죽인 거야, 너는.","JPN":"……あまりにも多くの人を殺したんだ、お前は。  ","ENG":"...You've killed too many people.","TWN":"……誰叫你殺人無數。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"살고 싶다면……. 목숨이라도 구걸해 봐.","JPN":"生きたければ……命乞いでもしてみなよ。","ENG":"If you want to live... try begging for your life.","TWN":"想活命的話……就求饒吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"아이…… 들은…….","JPN":"子ども……たちは……","ENG":"The... other maids...","TWN":"其……其他……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"다른 아이들은…… 아무 잘못…….","JPN":"他の子どもたちは……何も悪くな……","ENG":"They had... nothing to do with...","TWN":"其他人……什麼都沒……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"너와 함께 일하는 애들은 건드리지 않아. 처단을 부탁 받은 살인마는 너 하나였으니까.","JPN":"あなたと一緒に働いてる子どもたちには手を出さない。処断を頼まれた殺人鬼はあなた一人だから。","ENG":"We won't harm the others. We were only recruited to take you out.","TWN":"和你一起共事的人我不會碰她們，畢竟委託人只要求除掉你這個殺人魔。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그러니 이제 끝이다. 베로니카.","JPN":"さよなら。ベロニカ。","ENG":"It's all over for you, Veronica.","TWN":"一切就到此為止，貝洛妮卡。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};